var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"그 여자는 샤레이드에서 가장 성공한 카운터예요.","JPN":"あの女は、シャレードでもっとも成功したカウンターです。","ENG":"She is the most successful Counter in all of Charade.","TWN":"那個女人是查雷德最成功的制裁者。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"경매에 나온 넘버링 태스크포스 라이선스를 돈으로 사들일 만큼.","JPN":"オークションに出たナンバリングタスクフォースライセンスを、お金で買い取るくらい。","ENG":"She's rich enough to buy a numbered TASKFORCE license in an auction.","TWN":"她甚至能夠砸錢買下拍賣的高級特遣勢力執照。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"처음 등장했을 당시에는, 모두가 동경하는 스타 플레이어였어요.","JPN":"最初に登場した時には、みんなが憧れるスタープレイヤーでした。","ENG":"When she first appeared, she was a star player beloved by everyone.","TWN":"剛出場的時候，她曾經是所有人憧憬的明星選手。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"언제나 정정당당하게 승리를 거두는 건틀렛의 우상.","JPN":"いつも正々堂々と勝利を収めるガントレットのアイドル。","ENG":"Gauntlet's idol, always winning fair and square.","TWN":"總是光明正大贏得比賽的聖鎧偶像。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"이번 건은 도가 지나쳤더군. 오지만디아스.","JPN":"今回の件は度が過ぎたな。オジマンディアス。","ENG":"You went too far this time, Ozymandias.","TWN":"你這次做得太過火了，奧茲曼迪亞斯。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L11_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"아이, 그냥 조용히 처리해 줘. 우리 사이에.","JPN":"もう、目をつぶってくれない？　他でもない私の頼みでしょ？","ENG":"Oh, come on. Just cover it up. You can do that for me, right?","TWN":"唉唷，我們是什麼關係？就私下幫我處理一下嘛。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L12_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"내가 다 알고 손을 댔겠어? 그냥 옛날 인연 때문에 좀 도와 주려다 그런 거지.","JPN":"全部知ってて手を出したわけじゃないわ。ただ、昔の縁でちょっと手伝ってあげようとしてこうなったの。","ENG":"It's not like I knew what would happen. It was all to help an old acquaintance.","TWN":"要是我知道的話怎麼會出手？我是看在過去的情分才幫忙的。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>의도는 좋았다</color> 같은 말도 있잖아.","JPN":"<color=#ffd34c>意図はよかった</color>って言葉もあるじゃない？","ENG":"You know how the saying goes: <color=#ffd34c>It's the thought that counts</color>.","TWN":"畢竟我的<color=#ffd34c>出發點是好的</color>嘛。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"이건 관리국과도 깊이 연관된 문제야. 더 이상은 개입하지 마라.","JPN":"これは管理局とも深く関わっている問題だ。これ以上は干渉するな。","ENG":"This is also related to the Administration. Do not interfere anymore.","TWN":"這件事關係到管理局，不准你再插手。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"벌벌 떠는 소리가 여기까지 들리겠네.","JPN":"ぶるぶる震える音、ここまで聞こえちゃうわね。","ENG":"I hear you trembling from right over there.","TWN":"從電話裡都聽得出來你的聲音在發抖呢。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"나 이제 집이야. 자세한 얘기는 얼굴 보고 얘기해.","JPN":"私、もう家に着いたわ。詳しい話は直接顔を合わせてしましょう。","ENG":"I'm home now. Let's talk more in person.","TWN":"我現在在家，詳細的事等見面再說吧。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"후후, 스캐빈저에서 선물도 보내 줬나 봐.","JPN":"ふふ、スカベンジャーからプレゼントも贈ってくれたようね。","ENG":"Fu fuu, it looks like Scavengers sent me a little gift.","TWN":"呵呵，清道夫還送禮物來給我嗎？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"오지만디아스, 플라티나가 널 언제까지 비호해 줄 거라고─","JPN":"オジマンディアス、プラチナがいつまでも君を庇護してくれると─","ENG":"Ozymandias, just how long do you think Platina is going to protect y–","TWN":"奧茲曼迪亞斯，你以為普拉提娜會保你到什麼時候—"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그러게나 말이야. 나도 궁금해지네.","JPN":"そうね。私も気になるわ。","ENG":"Tell me about it. I'm curious myself.","TWN":"就是說，我也很好奇呢。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"어디 보자, 오늘 파티 일정이~","JPN":"どれどれ、今日のパーティースケジュールは～","ENG":"Let's see, today's party schedule is...","TWN":"我來看看今天的派對行程～"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"음? 격발음?","JPN":"うん？　撃発の音？","ENG":"Hmm? This sound is?","TWN":"嗯？爆炸聲？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"어떻게 됐어? 성공했나?","JPN":"どうなった？　成功したのか？","ENG":"How did it go? Did you succeed?","TWN":"怎麼樣？成功了嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L32_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"격발 성공했습니다. 펜트 하우스가 활활 타고 있어요.","JPN":"撃発に成功しました。ペントハウスが燃え上がっています。","ENG":"Shot confirmed. The penthouse is on fire.","TWN":"成功引爆，頂樓現在陷入一片火海。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"제대로 기폭된 것 같습니다만…. 상대가 그 오지만디아스인데….","JPN":"ちゃんと起爆したようですが……相手はあのオジマンディアスなので……","ENG":"It looks like it's been detonated properly... But we're talking about Ozymandias here...","TWN":"雖然成功引爆…但對方可是奧茲曼迪亞斯…"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"일하는 꼬라지 봤지? 그 년은 한참 전에 썩었어.","JPN":"働きぶりを見ただろう？　あの女、とっくに腐ってやがる。","ENG":"You've seen how she works. She's way past her prime.","TWN":"你沒看到她做事時的副德性嗎？她早就不行啦！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"우릴 파산하게 만들고 파티 갈 생각이나 하잖냐.","JPN":"私たちを破産させておいて、パーティーだけを考えていたではないか。","ENG":"Look at her, she's thinking of attending a goddamn party after making us go bankrupt!","TWN":"把我們弄破產還想著要參加派對？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"제대로 된 액션도 없이!","JPN":"ちゃんとしたアクションもないまま！","ENG":"Without any formal action, even!","TWN":"根本就毫無作為！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그야 스미스 아저씨보다 파티가 재밌으니까 그렇지.","JPN":"そりゃあ、スミスおじさんよりパーティーの方が面白いからよ。","ENG":"That's because parties are way more fun than Smith.","TWN":"那是因為派對比史密斯大叔更有趣的嘛。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"이 목소리는…… 오지만디아스?","JPN":"この声は……オジマンディアス？","ENG":"That voice... Ozymandias?","TWN":"這聲音是……奧茲曼迪亞斯？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"네, 네가 어떻게? 폭발이 일어난 곳에서 몇 블록은 떨어진 곳인데?","JPN":"ど、どうしてお前が？　爆発が起きたところから数ブロックは離れたところなのに。","ENG":"B-but how? It's blocks away from the place of the explosion!","TWN":"你，你怎麼會在那裡？這裡距離發生爆炸的地方好幾個街口呢？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭐? 아저씨, 어지간히도 감이 죽었네.","JPN":"はあ？　おじさん、本当に鈍ってるわね。","ENG":"What? You've lost your senses, old man.","TWN":"嗯？大叔，你真的變遲鈍囉。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"잠깐만. 잠깐, 그럴 리가. 너는……. 넌…….","JPN":"待て。ちょっと、そんなはずは。お前は……お前は……","ENG":"Wait. No. No way. You... You are...","TWN":"等一下，等等，這怎麼可能？你……你……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"응, 응. 하도 출전 안 해서 퇴물 된 줄 알았구나. 그럴 수도 있지, 뭐.","JPN":"うん、うん。滅多に出場しないから、衰えたと思ったの？　まあ、わかるわ。","ENG":"Yes, yes way. You thought I was trash because I didn't enter for a while, did you? Understandable.","TWN":"嗯，因為我太久沒參賽，所以你把我當病貓嗎？也是可以理解啦。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그런데 어쩌지. 내가 출전 안 하는 건 요즘 수준이 너무 떨어져서거든.","JPN":"でも、どうしよう。私が出場していない理由は、最近試合の質が落ちたからなのよ。","ENG":"Sorry to ruin the fun, but guess what? I don't enter because nothing's fun anymore at the Gauntlet.","TWN":"不過，我之所以不參賽，是因為最近的選手都水準太低。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"너, 너 선수가 이래도 돼? 어? 사람을 말이야! 뭘로 보고!","JPN":"せ、選手なのに、こんなことしていいと思ってるのか？　ああ？　人をなめやがって！","ENG":"Y-you shouldn't be doing this when you're a player! W-who do you think I am?","TWN":"你，你身為選手這樣沒問題嗎？你以為我是好惹的嗎！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"도망칠 생각 하지 말고 거기 가만히 있어.","JPN":"逃げようとしてないで、そこにじっとしててちょうだい。","ENG":"Don't you dare try to run away. Stay where you are.","TWN":"別想逃，就乖乖待在那裡。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"파티 가는 길에 들를 테니까.","JPN":"パーティーのついでに、そこに寄っていくから。","ENG":"I'll drop by on my way to the party.","TWN":"我去派對的路上順便解決你們。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"전승 무패. 관리국 공인 S급 카운터.","JPN":"全勝無敗。管理局公認のSランクカウンター。","ENG":"The undefeated, Administration confirmed Grade S Counter.","TWN":"百戰百勝，管理局公認的S級制裁者。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"오지만디아스.","JPN":"オジマンディアス。","ENG":"Ozymandias.","TWN":"奧茲曼迪亞斯。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"그 여자가…. 우리 엄마 아빠를 죽게 만든 원흉이에요.","JPN":"あの女が……私のママとパパを死なせた元凶です。","ENG":"She is the reason why my parents are dead.","TWN":"那女人……就是害死我爸爸媽媽的兇手。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};